'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { useAuth } from '@/app/auth-context'
import type { UserRole } from '@/lib/types'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Book, Mail, Lock, User } from 'lucide-react'
import Link from 'next/link'

export default function AuthPage() {
  const router = useRouter()
  const { login, register } = useAuth()
  const [isLogin, setIsLogin] = useState(true)
  const [isLoading, setIsLoading] = useState(false)
  const [selectedRole, setSelectedRole] = useState<UserRole>('ADHERENT')
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
  })

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target
    setFormData(prev => ({ ...prev, [name]: value }))
  }

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsLoading(true)
    try {
      if (!formData.email || !formData.password) {
        alert('Veuillez remplir tous les champs')
        return
      }
      const u = await login(formData.email, formData.password)
      router.push(u.role === 'ADHERENT' ? '/adherent' : '/bibliothecaire')
    } catch (error) {
      console.error('Login error:', error)
      alert(error instanceof Error ? error.message : 'Erreur de connexion')
    } finally {
      setIsLoading(false)
    }
  }

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsLoading(true)
    try {
      if (!formData.name || !formData.email || !formData.password) {
        alert('Veuillez remplir tous les champs')
        return
      }
      // Utilise l’API backend
      await register(formData.name, formData.email, formData.password, selectedRole)
      router.push(selectedRole === 'ADHERENT' ? '/adherent' : '/bibliothecaire')
    } catch (error) {
      console.error('Registration error:', error)
      alert(error instanceof Error ? error.message : "Erreur lors de l'inscription")
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-background to-muted flex items-center justify-center p-4">
      <div className="w-full max-w-md space-y-6 animate-fadeIn">
        {/* Logo */}
        <div className="flex justify-center animate-slideInDown">
          <div className="w-16 h-16 bg-primary rounded-xl flex items-center justify-center shadow-lg hover-scale">
            <Book className="text-primary-foreground" size={32} />
          </div>
        </div>

        <Card className="border-0 shadow-lg animate-slideInUp hover-lift">
          <CardHeader className="space-y-2">
            <CardTitle className="text-2xl">
              {isLogin ? 'Bienvenue' : 'Créer un compte'}
            </CardTitle>
            <CardDescription>
              {isLogin
                ? 'Connectez-vous à votre compte BibliO'
                : 'Créez votre compte pour accéder à BibliO'}
            </CardDescription>
          </CardHeader>

          <CardContent>
            <form onSubmit={isLogin ? handleLogin : handleRegister} className="space-y-4 stagger-item">
              {/* Registration role selection */}
              {!isLogin && (
                <div className="space-y-3">
                  <label className="text-sm font-medium">Type de compte</label>
                  <div className="grid grid-cols-2 gap-2">
                    {(['ADHERENT', 'BIBLIOTHECAIRE'] as UserRole[]).map(role => (
                      <button
                        key={role}
                        type="button"
                        onClick={() => setSelectedRole(role)}
                        className={`p-3 rounded-lg border-2 transition-colors text-sm font-medium ${
                          selectedRole === role
                            ? 'border-primary bg-primary/10 text-primary'
                            : 'border-border text-foreground hover:border-primary'
                        }`}
                      >
                        {role === 'ADHERENT' ? 'Adhérent' : 'Bibliothécaire'}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Name field (registration only) */}
              {!isLogin && (
                <div className="space-y-2">
                  <label htmlFor="name" className="text-sm font-medium">
                    Nom complet
                  </label>
                  <div className="relative">
                    <User className="absolute left-3 top-3 text-muted-foreground" size={18} />
                    <Input
                      id="name"
                      name="name"
                      placeholder="Jean Dupont"
                      value={formData.name}
                      onChange={handleInputChange}
                      className="pl-10"
                      disabled={isLoading}
                    />
                  </div>
                </div>
              )}

              {/* Email field */}
              <div className="space-y-2">
                <label htmlFor="email" className="text-sm font-medium">
                  Email
                </label>
                <div className="relative">
                  <Mail className="absolute left-3 top-3 text-muted-foreground" size={18} />
                  <Input
                    id="email"
                    name="email"
                    type="email"
                    placeholder={isLogin ? 'vous@example.com' : 'jean@university.edu'}
                    value={formData.email}
                    onChange={handleInputChange}
                    className="pl-10"
                    disabled={isLoading}
                  />
                </div>
                {isLogin && (
                  <p className="text-xs text-muted-foreground">
                    Conseil: utilisez "biblio@" pour un compte bibliothécaire
                  </p>
                )}
              </div>

              {/* Password field */}
              <div className="space-y-2">
                <label htmlFor="password" className="text-sm font-medium">
                  Mot de passe
                </label>
                <div className="relative">
                  <Lock className="absolute left-3 top-3 text-muted-foreground" size={18} />
                  <Input
                    id="password"
                    name="password"
                    type="password"
                    placeholder="••••••••"
                    value={formData.password}
                    onChange={handleInputChange}
                    className="pl-10"
                    disabled={isLoading}
                  />
                </div>
              </div>

              {/* Submit button */}
              <Button
                type="submit"
                className="w-full bg-primary hover:bg-primary/90 text-primary-foreground transition-smooth hover-scale disabled:opacity-50"
                disabled={isLoading}
              >
                {isLoading ? (
                  <span className="flex items-center justify-center gap-2">
                    <span className="w-4 h-4 border-2 border-primary-foreground border-t-transparent rounded-full animate-spin" />
                    Chargement...
                  </span>
                ) : isLogin ? 'Se connecter' : "S'inscrire"}
              </Button>
            </form>

            {/* Toggle form */}
            <div className="mt-6 pt-6 border-t border-border">
              <p className="text-center text-sm text-muted-foreground">
                {isLogin ? 'Pas encore de compte?' : 'Déjà inscrit?'}{' '}
                <button
                  onClick={() => setIsLogin(!isLogin)}
                  className="text-primary hover:underline font-medium"
                >
                  {isLogin ? "S'inscrire" : 'Se connecter'}
                </button>
              </p>
            </div>

            {/* Demo credentials hint */}
            <div className="mt-4 p-3 bg-muted rounded-lg text-xs text-muted-foreground space-y-1">
              <p className="font-medium">Comptes de démonstration:</p>
              <p>• Adhérent: adhérent@demo.com</p>
              <p>• Bibliothécaire: biblio@demo.com</p>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  )
}
